import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, Validators } from '@angular/forms';
import { ExpensesService, ExpenseItem } from '../../services/expenses.service';

@Component({
  selector: 'app-expenses',
  templateUrl: './expenses.component.html',
  styleUrls: ['./expenses.component.css']
})
export class ExpensesComponent implements OnInit {
  expenseItems: ExpenseItem[] = [];
  filteredItems: ExpenseItem[] = [];
  showForm = false;
  editingItem: ExpenseItem | null = null;
  searchTerm = '';
  loading = false;
  error: string | null = null;

  // Date filtering
  selectedYear: number = new Date().getFullYear();
  selectedMonth: number = new Date().getMonth();
  viewMode: 'all' | 'yearly' | 'monthly' | 'daily' = 'all';
  availableYears: number[] = [];
  availableMonths: string[] = [
    'January', 'February', 'March', 'April', 'May', 'June',
    'July', 'August', 'September', 'October', 'November', 'December'
  ];

  expenseForm: FormGroup;

  constructor(
    private expensesService: ExpensesService,
    private fb: FormBuilder
  ) {
    this.expenseForm = this.fb.group({
      date: ['', Validators.required],
      category: ['', Validators.required],
      amount: ['', [Validators.required, Validators.min(0)]],
      description: ['']
    });
  }

  ngOnInit(): void {
    this.loadExpenses();
    this.generateAvailableYears();
  }

  loadExpenses(): void {
    this.loading = true;
    this.error = null;
    this.expensesService.getAllExpenses().subscribe({
      next: (data) => {
        this.expenseItems = data;
        this.applyFilters();
        this.loading = false;
      },
      error: (error) => {
        this.error = 'Failed to load expenses data';
        this.loading = false;
        console.error('Error loading expenses:', error);
      }
    });
  }

  generateAvailableYears(): void {
    const currentYear = new Date().getFullYear();
    this.availableYears = [];
    for (let year = currentYear - 5; year <= currentYear + 1; year++) {
      this.availableYears.push(year);
    }
  }

  applyFilters(): void {
    let filtered = [...this.expenseItems];

    // Apply search filter
    if (this.searchTerm.trim()) {
      const term = this.searchTerm.toLowerCase();
      filtered = filtered.filter(item =>
        item.category.toLowerCase().includes(term) ||
        item.description?.toLowerCase().includes(term) ||
        item.amount.toString().includes(term)
      );
    }

    // Apply date filters
    if (this.viewMode === 'yearly') {
      filtered = filtered.filter(item => {
        const itemDate = new Date(item.date);
        return itemDate.getFullYear() === this.selectedYear;
      });
    } else if (this.viewMode === 'monthly') {
      filtered = filtered.filter(item => {
        const itemDate = new Date(item.date);
        return itemDate.getFullYear() === this.selectedYear &&
               itemDate.getMonth() === this.selectedMonth;
      });
    } else if (this.viewMode === 'daily') {
      const today = new Date();
      filtered = filtered.filter(item => {
        const itemDate = new Date(item.date);
        return itemDate.toDateString() === today.toDateString();
      });
    }

    this.filteredItems = filtered;
  }

  onSearch(): void {
    this.applyFilters();
  }

  onViewModeChange(): void {
    this.applyFilters();
  }

  onYearChange(): void {
    this.applyFilters();
  }

  onMonthChange(): void {
    this.applyFilters();
  }

  openAddForm(): void {
    this.editingItem = null;
    this.expenseForm.reset();
    this.expenseForm.patchValue({
      date: new Date().toISOString().split('T')[0] // Today's date
    });
    this.showForm = true;
  }

  editItem(item: ExpenseItem): void {
    this.editingItem = item;
    this.expenseForm.patchValue({
      date: item.date,
      category: item.category,
      amount: item.amount,
      description: item.description || ''
    });
    this.showForm = true;
  }

  cancelForm(): void {
    this.showForm = false;
    this.editingItem = null;
    this.expenseForm.reset();
  }

  onSubmit(): void {
    if (this.expenseForm.valid) {
      const formValue = this.expenseForm.value;

      if (this.editingItem) {
        // Update existing item
        this.expensesService.updateExpense(this.editingItem.id!, formValue).subscribe({
          next: () => {
            this.loadExpenses();
            this.cancelForm();
          },
          error: (error) => {
            this.error = 'Failed to update expense item';
            console.error('Error updating expense:', error);
          }
        });
      } else {
        // Create new item
        this.expensesService.createExpense(formValue).subscribe({
          next: () => {
            this.loadExpenses();
            this.cancelForm();
          },
          error: (error) => {
            this.error = 'Failed to create expense item';
            console.error('Error creating expense:', error);
          }
        });
      }
    } else {
      this.expenseForm.markAllAsTouched();
    }
  }

  deleteItem(item: ExpenseItem): void {
    if (confirm(`Are you sure you want to delete this ${item.category} expense?`)) {
      this.expensesService.deleteExpense(item.id!).subscribe({
        next: () => {
          this.loadExpenses();
        },
        error: (error) => {
          this.error = 'Failed to delete expense item';
          console.error('Error deleting expense:', error);
        }
      });
    }
  }

  getTotalExpenses(): number {
    return this.filteredItems.reduce((total, item) => total + item.amount, 0);
  }

  getFormFieldError(fieldName: string): string {
    const field = this.expenseForm.get(fieldName);
    if (field?.errors && field.touched) {
      if (field.errors['required']) {
        return `${fieldName.charAt(0).toUpperCase() + fieldName.slice(1)} is required`;
      }
      if (field.errors['min']) {
        return `${fieldName.charAt(0).toUpperCase() + fieldName.slice(1)} must be positive`;
      }
    }
    return '';
  }

  trackById(index: number, item: ExpenseItem): string {
    return item.id || index.toString();
  }

  getCategoryClass(category: string): string {
    return 'category-' + category.toLowerCase().replace(/\s+/g, '-');
  }
}
<div class="expenses-page">
  <div class="page-header">
    <div>
      <h1>Expenses Management</h1>
      <p>Track operational costs, supplies, and maintenance expenses</p>
    </div>
    <div class="header-actions">
      <a routerLink="/dashboard" class="btn btn-secondary">Dashboard</a>
      <button (click)="openAddForm()" class="btn btn-primary">
        <span>➕</span>
        Add Expense
      </button>
    </div>
  </div>

  <!-- Error Message -->
  <div *ngIf="error" class="alert alert-error">
    <span>⚠️</span>
    {{ error }}
    <button (click)="error = null" class="alert-close">×</button>
  </div>

  <!-- Stats Card -->
  <div class="stats-card">
    <div class="stat-item">
      <div class="stat-label">Total Expenses</div>
      <div class="stat-value">${{ getTotalExpenses() | number:'1.0-0' }}</div>
    </div>
    <div class="stat-item">
      <div class="stat-label">Filtered Entries</div>
      <div class="stat-value">{{ filteredItems.length }}</div>
    </div>
  </div>

  <!-- Search and Filters -->
  <div class="filters-section">
    <div class="search-box">
      <input
        type="text"
        placeholder="Search by category, description, or amount..."
        [(ngModel)]="searchTerm"
        (input)="onSearch()"
        class="form-input">
      <span class="search-icon">🔍</span>
    </div>

    <div class="date-filters">
      <div class="filter-group">
        <label>View Mode:</label>
        <select [(ngModel)]="viewMode" (change)="onViewModeChange()" class="filter-select">
          <option value="all">All Time</option>
          <option value="yearly">Yearly</option>
          <option value="monthly">Monthly</option>
          <option value="daily">Today</option>
        </select>
      </div>

      <div class="filter-group" *ngIf="viewMode === 'yearly' || viewMode === 'monthly'">
        <label>Year:</label>
        <select [(ngModel)]="selectedYear" (change)="onYearChange()" class="filter-select">
          <option *ngFor="let year of availableYears" [value]="year">{{year}}</option>
        </select>
      </div>

      <div class="filter-group" *ngIf="viewMode === 'monthly'">
        <label>Month:</label>
        <select [(ngModel)]="selectedMonth" (change)="onMonthChange()" class="filter-select">
          <option *ngFor="let month of availableMonths; let i = index" [value]="i">{{month}}</option>
        </select>
      </div>
    </div>
  </div>

  <!-- Expense Form Modal -->
  <div *ngIf="showForm" class="modal-overlay" (click)="cancelForm()">
    <div class="modal-content" (click)="$event.stopPropagation()">
      <div class="modal-header">
        <h2>{{ editingItem ? 'Edit' : 'Add' }} Expense Entry</h2>
        <button (click)="cancelForm()" class="modal-close">×</button>
      </div>

      <form [formGroup]="expenseForm" (ngSubmit)="onSubmit()" class="expense-form">
        <div class="form-row">
          <div class="form-group">
            <label class="form-label">Date *</label>
            <input
              type="date"
              formControlName="date"
              class="form-input"
              [class.error]="getFormFieldError('date')">
            <div *ngIf="getFormFieldError('date')" class="field-error">
              {{ getFormFieldError('date') }}
            </div>
          </div>

          <div class="form-group">
            <label class="form-label">Category *</label>
            <select formControlName="category" class="form-select" [class.error]="getFormFieldError('category')">
              <option value="">Select category</option>
              <option value="Food">Food</option>
              <option value="Transportation">Transportation</option>
              <option value="Entertainment">Entertainment</option>
              <option value="Utilities">Utilities</option>
              <option value="Maintenance">Maintenance</option>
              <option value="Marketing">Marketing</option>
              <option value="Supplies">Supplies</option>
              <option value="Other">Other</option>
            </select>
            <div *ngIf="getFormFieldError('category')" class="field-error">
              {{ getFormFieldError('category') }}
            </div>
          </div>
        </div>

        <div class="form-row">
          <div class="form-group">
            <label class="form-label">Amount *</label>
            <div class="amount-input">
              <span class="currency-symbol">$</span>
              <input
                type="number"
                formControlName="amount"
                placeholder="0.00"
                step="0.01"
                min="0"
                class="form-input amount-field"
                [class.error]="getFormFieldError('amount')">
            </div>
            <div *ngIf="getFormFieldError('amount')" class="field-error">
              {{ getFormFieldError('amount') }}
            </div>
          </div>

          <div class="form-group">
            <label class="form-label">Description</label>
            <input
              type="text"
              formControlName="description"
              placeholder="Optional description"
              class="form-input">
          </div>
        </div>

        <div class="form-actions">
          <button type="button" (click)="cancelForm()" class="btn btn-secondary">Cancel</button>
          <button type="submit" [disabled]="!expenseForm.valid" class="btn btn-primary">
            {{ editingItem ? 'Update' : 'Add' }} Expense
          </button>
        </div>
      </form>
    </div>
  </div>

  <!-- Data Table -->
  <div class="table-container" *ngIf="!loading">
    <table class="data-table" *ngIf="filteredItems.length > 0; else noData">
      <thead>
        <tr>
          <th>Date</th>
          <th>Category</th>
          <th>Amount</th>
          <th>Description</th>
          <th>Actions</th>
        </tr>
      </thead>
      <tbody>
        <tr *ngFor="let item of filteredItems; trackBy: trackById" [class]="getCategoryClass(item.category)">
          <td>{{item.date | date:'shortDate'}}</td>
          <td>{{item.category}}</td>
          <td class="amount-cell">${{item.amount | number:'1.2-2'}}</td>
          <td>{{item.description || '-'}}</td>
          <td class="actions-cell">
            <button class="btn btn-edit" (click)="editItem(item)">Edit</button>
            <button class="btn btn-delete" (click)="deleteItem(item)">Delete</button>
          </td>
        </tr>
      </tbody>
    </table>

    <ng-template #noData>
      <div class="no-data">
        <p>No expenses found for the selected filters.</p>
      </div>
    </ng-template>
  </div>
</div>
